var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"가라!! 에잇!","JPN":"行け！！　えいっ！","ENG":"Take that!! Hyah!","TWN":"走開！去去！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으아앙! 잘못했어요! 이제 안 때릴게!","JPN":"ふええん！　ごめんなさい！　もう叩かないから！","ENG":"Waah! I'm sorry! I won't hit you again!","TWN":"嗚嗚嗚！對不起！我不該打你的！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"노엘 양, 교량으로 진입했나?","JPN":"ノエル君、橋まで来たかね？","ENG":"Noelle, are you at the bridge?","TWN":"洛艾兒小姐，你上橋了嗎？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네에에엣! 거의 다 왔어요! 이제 어떻게 하면 돼요?","JPN":"はいいいいっ！　もうすぐです！　これからどうすればいいんですか？","ENG":"Almost there! What do I have to do next?","TWN":"是！！！我快到了！那接下來該怎麼辦呢？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 일대는 오랫동안 침식재난 구역으로 지정되어서 시설 관리도 소홀했다네.","JPN":"そこら一帯は長らく侵食災害区域として指定されていたから、施設の管理もなおざりにされている。","ENG":"That area has been designated as a Corruption disaster zone for a long time, so it has not been well maintained.","TWN":"那個地方長期被認定是侵蝕災難地區，因此疏於管理。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 다루는 무기라면 교각을 파괴해서 다리를 무너뜨릴 수 있을 거야.","JPN":"君の武器なら、橋脚を破壊して橋を崩せるはずだ。","ENG":"You should be able to destroy the bridge joints and collapse the bridge with your weapon.","TWN":"你的武器應該可以破壞橋墩讓橋崩塌。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런 일이 가능할까요? 전 오늘 침식체랑도 처음 싸워 보는데요?!","JPN":"私にできるんでしょうか？　侵食体とも戦うのも今日が初めてなんですけど！？","ENG":"Do you think that's really possible? I mean, it's my first time fighting a C.O. today!","TWN":"我做得到嗎？我今天才第一次嘗試對付侵蝕體欸？！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"실패하면 함께 있던 부상자들의 안전은 장담할 수 없을 걸세.","JPN":"失敗すれば一緒にいた怪我人たちの安全は保証できない。","ENG":"If you fail, I cannot guarantee the safety of the people you were with.","TWN":"萬一失敗的話，那就無法保證那些傷者的安全無虞。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"납치범이나 할 것 같은 협박을! 저 조금 식겁했어요!","JPN":"誘拐犯が言いそうな脅し文句！　私、ちょっとぞっとしました！","ENG":"Whoa, you just sounded like a kidnapper threatening his victim! I got chills running down my spine!","TWN":"怎麼這麼像綁架犯威脅人時說的話！我有點嚇到欸！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"하지만 무슨 뜻인지는 알겠어요!","JPN":"でも、どういうことなのかはわかります！","ENG":"But yes, I get what you mean!","TWN":"不過我明白老闆的意思了！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"도전! 지금부터 다리를 무너뜨려 보겠습니다!","JPN":"挑戦！　今から橋を崩してみます！","ENG":"Challenge accepted! I'll try to bring down that bridge!","TWN":"挑戰！我現在就把橋弄塌！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"부탁해, 바즈라!","JPN":"お願い、ヴァジュラ！","ENG":"I'm counting on you, Vajra!","TWN":"拜託囉，金剛杵！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐이익?!","JPN":"ふええっ！？","ENG":"Eeeek!!","TWN":"欸欸？！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_EX","text":{"KOREA":"이리 와!! 이 역겨운 계집애야아아아아!","JPN":"こっち来い！！　このムカつく小娘ええええ！","ENG":"Come here!! You filthy little girl!!!","TWN":"給我過來！！你這個臭丫頭！！！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님! 다리가 안 무너져요!","JPN":"社長！　橋が崩れません！","ENG":"Boss! The bridge won't collapse!","TWN":"老闆！橋沒有塌欸！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"한두 개로는 부족할 걸세. 침식체가 덮치기 전에 서두르게.","JPN":"一つ二つでは足りないだろう。侵食体が襲ってくる前に急ぐんだ。","ENG":"You will need to destroy more than a couple. Hurry, before the C.O. gets to you.","TWN":"看來破壞一、二個橋墩是不夠的。動作快，侵蝕體就快撲上來了！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네, 네엣!","JPN":"は、はいっ！","ENG":"O-okay!","TWN":"是，是！！！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_EX","text":{"KOREA":"깔깔깔깔!! 너도 으스러뜨려 줄 거야!","JPN":"ゲラゲラゲラ！！　お前もぶっ潰してやる！","ENG":"Gahahaha!! I will crush you too!","TWN":"嘿嘿嘿！！你也會完蛋的！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L34_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_EX","text":{"KOREA":"으스러뜨리고 으스러뜨려다 개밥으로 던져 줄 거라고오오오! 깔깔깔깔!","JPN":"ぶっ潰してぶっ潰して犬のエサにしてやるんだよおおお！　ゲラゲラゲラゲラ！","ENG":"I will crush you, grind you, then feed you to the dogs! Bwahahaha!","TWN":"我要撕爛你，再把你扔去餵狗！！！嘿嘿嘿！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"잡히면 끝이야! 제발 이번에는 무너져라, 무너져라, 무너져라…!","JPN":"捕まったら終わりだよ！　お願い、今度こそ崩れろ、崩れろ、崩れろ……！","ENG":"It'll be game over if it catches me! Please collapse this time. Please, oh please...!","TWN":"被逮到的話就完啦！拜託這次一定要塌，拜託拜託…！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"가라, 바즈라!","JPN":"行け、ヴァジュラ！","ENG":"Go, Vajra!","TWN":"去吧，金剛杵！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_EX","text":{"KOREA":"아아아아아아악!","JPN":"ああああああああ！","ENG":"Aaaagh!","TWN":"啊啊啊啊啊啊！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"해냈다…! 들리세요, 사장님? 성공했어요!","JPN":"やった……！　聞こえますか、社長？　成功しました！","ENG":"I did it...! Can you hear me, Boss? I did it!","TWN":"我做到了…！老闆，你有聽到嗎？我成功了！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 상부에 돌출된 얼굴이 약점일세. 그걸 노리게나.","JPN":"よし。上層部にとび出ている顔が弱点だ。そこを狙うんだ。","ENG":"Very good. The face that's protruding from the top is its weak spot. Aim for that.","TWN":"非常好，弱點應該是上面露出臉的部分，瞄準那裡！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"알겠습니다! 억울하게 돌아가신 아저씨들의 원한까지 확실하게 갚아 줄게요!","JPN":"わかりました！　無念に亡くなったおじさんたちの仇もきっちり取ってあげます！","ENG":"Roger! I'll make sure to avenge those men you've killed!","TWN":"好的！我要為那些無辜死去的大叔報仇！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"궤도 구축 개시!","JPN":"軌道構築開始！","ENG":"Commencing orbital construction!","TWN":"開始建構軌道！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"조준──!","JPN":"照準――！","ENG":"Aim──!","TWN":"瞄準──！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HYPER_ATTACK_START"},{"id":"L47_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_EX","text":{"KOREA":"이 개 같은 계집애……!!","JPN":"このクソガキ……！！","ENG":"Why you little...!!","TWN":"你這臭丫頭……！！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_EX","text":{"KOREA":"이리 와!! 이리 안 와아아아아!!","JPN":"来い！！　こっち来いよおおおお！！","ENG":"Get over here!! I said get over here!!","TWN":"給我過來！！還不過來！！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"발사!!","JPN":"発射！！","ENG":"Fire!!","TWN":"發射！！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"하아…. 하아…. 하아….","JPN":"はあ……はあ……はあ……","ENG":"*Huff*... *Huff*... *Huff*...","TWN":"呼呼…呼呼…呼呼…"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"휴우으으…. 살았다…. 죽는 줄 알았네….","JPN":"ふううう……助かった……死ぬかと思ったよ……","ENG":"Phew... I thought I was a goner...","TWN":"呼…得救了…我還以為會死掉…"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"곧 부사장이 거기 도착할 걸세. 조금만 기다리게.","JPN":"もうすく副社長がそこに着くはずだ。少しだけ待機してくれたまえ。","ENG":"The Vice President will arrive shortly. Just hang in there.","TWN":"副總就快趕到了，你再等一下。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무리 취약점을 노렸다지만 마지막 공격은 상당한 위력이었어. 훌륭하군.","JPN":"弱点を狙ったといえ、最後の攻撃の威力はすごかった。さすがだな。","ENG":"That last strike was flawless. Even if it was its weak spot, it was a critical blow. Excellent work.","TWN":"雖然是瞄準弱點，但你最後一擊的威力很強呢，非常出色。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헤헤, 사장님 덕분이죠. 사장님이 전화 안 해 주셨으면 큰일날 뻔했어요.","JPN":"へへ、社長のおかげです。社長が電話してくれなかったら、大変なことになってました。","ENG":"He he. It's all thanks to you, Boss. If you didn't call me, I'd be in big trouble right now.","TWN":"嘿嘿，這都是拜老闆所賜，要是老闆沒打來肯定會完蛋。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗……?!","JPN":"あっ……！？","ENG":"Huh...?!","TWN":"啊……？！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"노엘 양? 왜 그러나?","JPN":"ノエル君？　どうしたかね？","ENG":"Noelle? What's wrong?","TWN":"洛艾兒小姐？你怎麼了？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님, 저기! 처음 나타났던 침식체예요!","JPN":"社長、あそこ！　最初に現れた侵食体です！","ENG":"Boss, over there! It's a C.O. that appeared at first.","TWN":"老闆，是一開始出現的侵蝕體！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"새로 만든. 침식체.","JPN":"新シイ。侵食体。","ENG":"New. C.O.","TWN":"新做的，侵蝕體。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"못 쓰게 만들었다.","JPN":"ダメニナッタ。","ENG":"Became useless.","TWN":"沒用。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"너. 만든다. 침식체를.","JPN":"オ前。作ル。侵食体ニ。","ENG":"Now. Make you. Into C.O.","TWN":"我要把你，做成侵蝕體。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님! 이쪽으로 오고 있어요!","JPN":"社長！　こっちに向かって来ます！","ENG":"Boss! It's coming towards me!","TWN":"老闆！它往這裡過來了！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"한 번 더 다리를 무너뜨릴까요? 하지만 이제 더 무너뜨릴 기둥도 없는데…!","JPN":"もう一度橋を崩しますか？　でも、もう崩す柱もないのに……！","ENG":"Should I collapse the bridge again? But there are no more pillars left...!","TWN":"我要再把橋弄塌嗎？可是現在沒有橋墩可以破壞咧…！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침착하게. 노엘 양.","JPN":"落ち着きたまえ。ノエル君。","ENG":"Calm down, Noelle.","TWN":"你冷靜一點，洛艾兒小姐。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"직원들이 막 도착한 모양이니까.","JPN":"ちょうど社員たちが着いたようだ。","ENG":"My employees seem to have arrived.","TWN":"我的員工們現在應該到了。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아슬아슬하게 제때 도착했군요. 교통 딱지를 몇 개나 뗄지는 모르겠지만요.","JPN":"ギリギリ間に合いましたね。切符を切られなくて幸いでした。","ENG":"We arrived just in the nick of time. Maybe I'll get several speeding tickets later.","TWN":"千鈞一髮之際趕上了呢，不知道會收到幾張罰單。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗! 부사장님! 유미나 님!","JPN":"あっ！　副社長！　ミナ様！","ENG":"Oh! Vice President! And Ms. Mina!","TWN":"哇！是副總！跟劉米娜小姐！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"절 구하러 와 주신 거예요? 정말 감동했어요!","JPN":"助けに来てくれたんですか？　感動です！","ENG":"Are you here to save me? I'm so touched!","TWN":"你們是來救我的嗎？好感動喔！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지원자를 사지로 내몰았다는 추문까진 만들고 싶진 않았으니까요. 호들갑 떨지 마세요.","JPN":"志願者を死地に追い込んだという噂まで流されたくはありませんので。大げさにしないでくださいね。","ENG":"Please calm down. We just do not want to cause a scandal and be blamed for an applicant's death.","TWN":"我只是不希望有公司把應徵者逼死的醜聞出現，不需要大驚小怪的。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"너희들. 인간.","JPN":"オ前タチ。人間。","ENG":"You. Humans.","TWN":"你們，人類。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"강한 인간.","JPN":"強イ人間。","ENG":"Strong.","TWN":"厲害的人類。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"거슬리게 하지 말고 당장 사라져. 침식체.","JPN":"目ざわりだから、とっとと消えて。侵食体。","ENG":"Quit bothering us and get out of our sight, C.O.","TWN":"少在這邊丟人現眼，快滾吧，侵蝕體。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"팔 하나 못 쓴다고 해도 너 하나 상대 못할 정도는 아니니까.","JPN":"腕一本使えなくても、あんたの相手くらいできるんだから。","ENG":"Even if I can't use one of my arms, I can still take you down.","TWN":"雖然我一隻手臂受傷，但對付你還是綽綽有餘的。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"너. 싸우지 않는다.","JPN":"オ前。戦ワナイ。","ENG":"You. Do not fight.","TWN":"你，不行。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……뭐?","JPN":"……は？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"침식체 주제에…. 멋대로 지껄이지 마.","JPN":"侵食体のくせに……勝手なこと言わないで。","ENG":"What do you know? You're just a C.O.","TWN":"你這個侵蝕體…在那邊給我鬼扯什麼！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"싸울 수 없다. 너.","JPN":"戦エナイ。オ前。","ENG":"You. Cannot fight.","TWN":"你，無法。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"약하다.","JPN":"弱イ。","ENG":"Weak.","TWN":"好弱。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"정신 공격이라도 당했어? 뭘 상대해 주고 있는 거야?","JPN":"精神攻撃にでもやられた？　何をまともに相手してるの。","ENG":"Did you get emotional damage or something? Why were you talking to him?","TWN":"你是受到精神攻擊嗎？跟它對話做什麼？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L48_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……샤오린?","JPN":"……シャオリン？","ENG":"...Xiao Lin?","TWN":"……曉琳？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"경계 유지해. 아직 살아 있어.","JPN":"警戒を解かないで。まだ生きているわ。","ENG":"Stay alert. He's not dead yet.","TWN":"保持警戒，它還沒死。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"크륵. 큭….","JPN":"グルル。グル……","ENG":"Krrr... Krgh...","TWN":"呃，呃呃…"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"이 위력. 좋은…. 정보가. 되었다.","JPN":"コノ威力。イイ……、情報ニ。ナッタ。","ENG":"This power. Good... Information.","TWN":"這個威力，是很好的…情報。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"인간의. 무기. 원한다.","JPN":"人間ノ。武器。ホシイ。","ENG":"I. Want. Human weapon.","TWN":"想要，人類的，武器。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"다음…… 에게. 부탁.","JPN":"次……ニ。頼ム。","ENG":"For... The. Next.","TWN":"下次……見。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"샤오린, 보고 있어?","JPN":"シャオリン、見てる？","ENG":"Xiao Lin, are you seeing this?","TWN":"曉琳，你有看到嗎？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그래. 먼지처럼 변해 그대로 흩어져 버렸어.","JPN":"うん。埃みたいになって、そのまま散ってしまった。","ENG":"Yeah. He turned into dust and disappeared.","TWN":"有，它化成灰後就消失了。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"통상의 침식체는 저런 형태로 죽지 않아. 일반적인 침식체는 아니야.","JPN":"通常の侵食体はあんな形で死ぬことはない。一般的な侵食体じゃないね。","ENG":"Normal C.O.s don't die like that. And that wasn't your typical C.O.","TWN":"通常侵蝕體是不會以那種狀態死去的，它不是一般的侵蝕體。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그림자라기엔… 3종 이하였어.","JPN":"シャドウだとしても……第3種以下だった。","ENG":"But to call him a Shadow... he was below Category 3.","TWN":"但還不到暗影的程度…應該是3類以下。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"회사 문제만으로도 머리가 터질 지경인데... 무슨 일이 일어나는 거지?","JPN":"会社の問題だけでも頭痛いのに……何が起きてるっていうの？","ENG":"My head feels like it's going to burst dealing with company issues... So what the heck happened here?","TWN":"光是公司的事就夠令人頭痛的了…是發生什麼事？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"유미나님!!","JPN":"ミナ様！！","ENG":"Ms. Mina!!","TWN":"劉米娜小姐！！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐, 뭐야? 끌어안지 말고 떨어져.","JPN":"な、何だよ？　抱きつかないで離れて。","ENG":"H-huh? Stop hugging me.","TWN":"你，你做什麼？不要抱著我，放開。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"침식체랑 맞서는 모습 너무너무 멋졌어요!","JPN":"侵食体と向き合う姿、めっちゃくちゃカッコよかったです！","ENG":"You looked so cool dealing with that C.O.!","TWN":"你對付侵蝕體的樣子真的超帥的！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"역시 영상보다 실물이 더 대단해! 저 오늘 이 순간을 절대 잊지 않을 거예요!","JPN":"やっぱり動画より本物の方がすごい！　私、今日のこの瞬間を絶対忘れません！","ENG":"It was even more epic in person than in the video! I'll never forget what happened today!","TWN":"現場看比影片裡更厲害呢！我絕對不會忘記這個瞬間的！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 맞다! 저 방금 전에 다른 침식체를 쓰러뜨렸거든요!","JPN":"あっ、そうだ！　私、さっき他の侵食体を倒したんですよ！","ENG":"Oh, right! I also took care of the other C.O.!","TWN":"啊，對了！我剛才打倒其他侵蝕體囉！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"물컹물컹해서 만지기 싫게 생겼는데 어떻게든 해냈어요!","JPN":"ぐにゃぐにゃしてて触りたくない姿でしたけど、何とかやりました！","ENG":"It was all squishy-looking and I didn't want to touch it, but I defeated it!","TWN":"雖然它長得一副軟軟爛爛的，光看就不想碰，但我還是做到了！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님께서 도와 주시긴 했지만, 저것도 혹시 3종 침식체인가요?","JPN":"社長が手伝ってくれたんですけど、あれももしかして第3種侵食体なんですか？","ENG":"Boss did help me a little, but could that one be a Category 3 C.O.?","TWN":"不過老闆有幫我啦。那個也是3類侵蝕體嗎？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"왜 그렇게 우리 소대에 들어오고 싶어서 안달인 거야?","JPN":"なんでそんなにうちの小隊に入りたがるの？","ENG":"Why are you so obsessed with joining our squad?","TWN":"你為什麼非進我們小隊不可？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Sorry?","TWN":"什麼？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"우린 신입에게 별로 친절하지 않아.","JPN":"うちは新人にあまり優しくないよ。","ENG":"We aren't that nice to newcomers.","TWN":"我們對新人很不友善。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"소대장은 언제나 막무가내식이고, 시윤 선배는 틈만 나면 농땡이 피울 생각만 하고.","JPN":"小隊長はいつも我がままで、先輩は暇があるとサボることばっかりで。","ENG":"Commander is always reckless, and Shiyoon slacks off whenever he gets the chance.","TWN":"小隊長固執己見，時雲前輩逮到機會就想偷懶。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나는…….","JPN":"私は……","ENG":"I...","TWN":"我呢……"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"어쨌거나, 네 상상만큼 펜릴 소대는 그렇게 멋진 곳도, 대단한 곳도 아니야.","JPN":"とにかく、フェンリル小隊はあなたが想像してるようにカッコいいところでも、すごいところでもないの。","ENG":"Anyway, Fenrir Squad isn't as glamorous or great as you think it is.","TWN":"總之，芬里爾小隊沒有你想像中厲害又帥氣。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"애초에 용병이라는 건 돈을 보고 하는 일이라고.","JPN":"大体、傭兵ってのはお金稼ぎ目当ての職業なんだよ。","ENG":"I mean, we are mercenaries who'd do anything for the right price.","TWN":"傭兵就是拿錢辦事吧？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럴 리가요!","JPN":"そんなはずありません！","ENG":"No, you aren't!","TWN":"才不是！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"유미나님은, 펜릴 소대는 세상을 구한 분들이잖아요!","JPN":"ミナ様は、フェンリル小隊は世界を救った方々じゃないですか！","ENG":"You and Fenrir Squad are heroes who saved the world, Ms. Mina!","TWN":"劉米娜小姐，芬里爾小隊是拯救世界的人！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"유미나님이 클리포트 게임을 막아서 많은 사람들을 구할 수 있었다고요!","JPN":"ミナ様がクリフォトゲームを阻止して、たくさんの人が助かったんです！","ENG":"Because you stopped the Qliphoth Game, many lives were saved!","TWN":"劉米娜小姐是可以阻止逆卡巴拉遊戲拯救許多人的！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……사람들.","JPN":"……たくさんの人。","ENG":"...Lives...","TWN":"……許多人。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"세상 사람들이 믿지 않더라도 저는 알고 있어요. 정말로요.","JPN":"世間の人たちが信じなくても、私は知ってます。本当です。","ENG":"Even if people don't believe it, I know it's true! I really do!","TWN":"就算世人不相信，但我很清楚。是真的！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 노엘도 그런 사람이 되고 싶습니다!","JPN":"だから、ノエルもそんな人になりたいんです！","ENG":"And I want to become someone like that!","TWN":"所以我也想成為這樣的人！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"세상을 구하는, 멋진 사람이요!","JPN":"世界を救う、カッコいい人に！","ENG":"An amazing person who saves the world!","TWN":"可以拯救世界的人！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘. 아쉽지만, 네가 쓰러뜨린 침식체는 3종 수준에는 못 미쳐.","JPN":"ノエル。残念だけど、あなたが倒した侵食体は第3種じゃない。","ENG":"Noelle, I'm sorry to burst your bubble but the C.O. you defeated was far from being a Category 3.","TWN":"洛艾兒，很可惜，你打倒的侵蝕體還不到3類的程度。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고요?! 맙소사!","JPN":"ええ！？　そんな！","ENG":"What?! But that can't be!","TWN":"你說什麼？！可惡！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L42_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그래도…….","JPN":"でも……","ENG":"However...","TWN":"不過……"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"생각이 있다면, 면접은 다시 보게 해 줄게.","JPN":"その気があるなら、面接はもう一回受けさせてあげる。","ENG":"If you're up for it, I'll let you retake the interview.","TWN":"你願意的話，我可以再替你安排一次面試。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"오전에는 나도 너무 성실하지 않게 했으니까.","JPN":"午前は私もあまり真面目にやらなかったから。","ENG":"I believe my attitude this morning was insincere as well.","TWN":"上午的時候，我有點口是心非。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저, 정말요?! 제가 지금 잘못 들은 거 아니죠?!","JPN":"ほ、本当ですか！？　私の聞き間違いじゃないですよね！？","ENG":"R-really?! I didn't mishear that, right?!","TWN":"是，真的嗎？！我沒聽錯吧？！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"만세!! 저 이번엔 꼭 통과할게요!","JPN":"やった！！　私、今度は絶対パスします！","ENG":"Yippee! I'll be sure to pass this time!","TWN":"萬歲！！這次我一定要通過面試！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"급한 불은 끈 모양이네요. 저희는 철수하겠습니다, 부사장님.","JPN":"急場はしのぎましたね。私たちは撤収します、副社長。","ENG":"Since the most urgent issue's been taken care of, we'll be heading back, Vice President.","TWN":"危機解除，那我們就先撤了，副總。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"돌아가서 푹 쉬어 두세요. 파산을 막으려면 불철주야 일해야 할 테니까요.","JPN":"帰ってゆっくり休んでください。破産しないようにするためには、昼夜の別なく働かないといけませんから。","ENG":"Make sure the rest once you get back. We're going to have to pull all-nighters to avoid going bankrupt.","TWN":"回去好好休息，之後必須要沒日沒夜的工作才能阻止公司倒閉了。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"수당만 제대로 챙겨 주신다면요.","JPN":"ちゃんと手当をくれるのでしたら。","ENG":"Only if you pay for overtime.","TWN":"有錢好辦事。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후우……. 숨 좀 돌리나 했더니.","JPN":"ふう……やっと息抜きできると思ったら。","ENG":"Whew... Just when I thought we might be able to catch our breath...","TWN":"呼……還以為可以稍微喘口氣，"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"골치 아픈 일이 끊이질 않네.","JPN":"面倒ごとが絶えないわね。","ENG":"Problems pop up left and right.","TWN":"結果煩人的事一波未平一波又起呢。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};